def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        exp_sum = 0.0
        for a in range(1, 10):
            inner_sum = 0.0
            for b in range(1, a+1):
                weight = (a * b) / (a + b + 1)
                inner_sum += weight * ((ratio + 0.1)**(a+b)) / ((a+b)**1.5)
            exp_sum += inner_sum * ((-1)**a) / a
        score += max(0, exp_sum)
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 3.0
            for check in range(1, 4):
                if abs(remaining - (capacity * 0.02 * check)) < 0.01 * capacity:
                    score *= 1.2 + 0.05 * check
        elif remaining < 0.15 * capacity:
            score *= 1.4 + 0.2 * np.sin(remaining / capacity * np.pi)
        else:
            score *= 0.65 + 0.3 * np.cos(ratio * np.pi / 2)
        prime_factors = [2, 3, 5, 7, 11]
        penalty_base = 0
        for p in prime_factors:
            if int(capacity) % p == 0:
                penalty_base += p * 0.03
            elif int(capacity + item) % p == 0:
                penalty_base += p * 0.015
            else:
                penalty_base -= p * 0.01
        if penalty_base < 0:
            penalty_base = 0
        score -= penalty_base
        run_bonus = 0
        for length in range(2, 7):
            product = 1
            close_count = 0
            for n in range(length):
                val = abs(capacity - item * (n+1))
                threshold = 0.02 * capacity * (n+1)
                product *= np.exp(-val/threshold)
                if val < threshold:
                    close_count += 1
            if close_count >= length // 2:
                run_bonus += product * 0.5 * length
        score += run_bonus
        if score < 0:
            score = 0
        if score > 2.0:
            multiplier = 1.0
            for div in range(1, 6):
                test_val = capacity / div
                deviation = abs(test_val - item)
                allowed = 0.025 * test_val
                if deviation < allowed:
                    multiplier += 0.08 * div
                elif deviation < 2 * allowed:
                    multiplier += 0.03 * div
                else:
                    multiplier -= 0.02 * div
            score *= max(multiplier, 0.9)
        priorities[i] = score
    return priorities
